"""QuantBench Phase 0 signal - generated by the Coordinator agent.

Runnable standalone: `python signal.py <data.parquet> [--output out.csv]`
"""
import numpy as np
import pandas as pd


def compute(df: pd.DataFrame) -> pd.Series:
    # 计算50日均线和200日均线
    ma50 = df['close'].rolling(window=50).mean()
    ma200 = df['close'].rolling(window=200).mean()
    
    # 信号：1 = 金叉做多（50上穿200），0 = 死叉空仓（50下穿200）
    # 用shift(1)确保因果性：用前一天的均线位置判断今天开盘时的信号
    prev_ma50 = ma50.shift(1)
    prev_ma200 = ma200.shift(1)
    
    # 金叉：前一日50<200，当日50>200
    golden_cross = (prev_ma50 <= prev_ma200) & (ma50 > ma200)
    # 死叉：前一日50>200，当日50<200
    death_cross = (prev_ma50 >= prev_ma200) & (ma50 < ma200)
    
    # 初始化信号为NaN（无持仓直到第一个信号）
    signal = pd.Series(0.0, index=df.index)
    
    # 记录持仓状态：使用迭代来保持因果性
    position = 0.0
    for i in range(len(df)):
        if i < 200:  # 需要200根K线才能计算均线
            continue
        if golden_cross.iloc[i]:
            position = 1.0
        elif death_cross.iloc[i]:
            position = 0.0
        signal.iloc[i] = position
    
    return signal

if __name__ == "__main__":
    import argparse
    import os
    import sys
    from contextlib import contextmanager

    sys.dont_write_bytecode = True
    parser = argparse.ArgumentParser()
    parser.add_argument("data_path")
    parser.add_argument("--output")
    args = parser.parse_args()

    @contextmanager
    def _suppress_native_stderr():
        stderr_fd = 2
        saved_fd = os.dup(stderr_fd)
        try:
            with open(os.devnull, "w") as devnull:
                os.dup2(devnull.fileno(), stderr_fd)
                yield
        finally:
            os.dup2(saved_fd, stderr_fd)
            os.close(saved_fd)

    with _suppress_native_stderr():
        _df = pd.read_parquet(args.data_path)

    if "symbol" in _df.columns:
        # Multi-symbol panel (Phase 1 cross-sectional runs). compute() must be
        # applied per symbol, in the exact same shape run_cross_sectional_backtest
        # uses internally - never across the mixed long table directly, or the
        # reproduced numbers will silently diverge from the real backtest.
        _frames = []
        for _symbol, _symbol_df in _df.groupby("symbol", sort=False):
            _symbol_df = _symbol_df.sort_values("timestamp").reset_index(drop=True)
            _out_symbol = _symbol_df[["timestamp"]].copy()
            _out_symbol["symbol"] = _symbol
            _out_symbol["signal"] = compute(_symbol_df)
            _frames.append(_out_symbol)
        _out = pd.concat(_frames, ignore_index=True).sort_values(["timestamp", "symbol"])
    else:
        _out = _df[["timestamp"]].copy()
        _out["signal"] = compute(_df)

    _csv = _out.to_csv(index=False)
    if args.output:
        with open(args.output, "w", encoding="utf-8") as handle:
            handle.write(_csv)
    else:
        print(_csv)
